const jdNodes = $('Fetch Job Description').all();
const jd = jdNodes.length > 0 ? jdNodes[0].json : {};

const resumes = $input.all();

let combinedResumesText = "";
resumes.forEach((r, idx) => {
  combinedResumesText += `\n\n--- CANDIDATE RESUME ${idx + 1} ---\n${r.json.text || 'Error extracting text'}`;
});

const prompt = `You are an expert HR recruiter and resume analyst.

**DYNAMIC JOB REQUIREMENTS:**
- **Position:** ${jd.job_title || 'Software Engineer'}
- **Required Skills:** ${jd.required_skills || 'Programming'}
- **Optional Skills:** ${jd.optional_skills || 'None'}
- **Experience Level:** ${jd.experience_level || 'Not Specified'}

**CANDIDATE RESUMES TO ANALYZE:**
${combinedResumesText}

**ANALYSIS INSTRUCTIONS:**
For EACH candidate, extract and analyze the following information:
1. Basic info (name, email, phone).
2. Professional background (current title, experience years).
3. Skills match against the required skills.
4. **Match Score (1-100)** weighted precisely as:
   - Heavy weight on REQUIRED SKILLS match (70% of score)
   - Bonus points for matching OPTIONAL SKILLS (15% of score)
   - Experience level, project quality, career trajectory (15% of score)

**CRITICAL OUTPUT REQUIREMENTS:**
Evaluate EVERY candidate provided above. You must return your analysis strictly as an object containing a "candidates" array matching the structured output tool schema.`;

return {
  json: {
    aiPrompt: prompt,
    job_id: jd.id
  }
};

let data = $input.first().json;

// Handle Markdown-wrapped JSON from Basic LLM Chain
let parsedData = data;
if (data.text) {
  let rawText = data.text;
  let jsonMatch = rawText.match(/```(?:json)?([\s\S]*?)```/);
  if (jsonMatch && jsonMatch[1]) {
    rawText = jsonMatch[1].trim();
  }
  try {
    parsedData = JSON.parse(rawText);
  } catch (e) {
    parsedData = { candidates: [] };
  }
}

// Extract nested outputs
if (parsedData.output) parsedData = parsedData.output;
let candidates = parsedData.candidates || parsedData;

if (!Array.isArray(candidates)) candidates = [candidates];

// Generate a unique screening_id and format as individual n8n items for next steps
return candidates.map(candidate => {
  return {
    json: {
      ...candidate,
      screening_id: 'scr_' + Date.now() + '_' + Math.random().toString(36).substr(2, 5)
    }
  };
});

// Process HR Selections & Generate MCQ Questions - UPDATED WITH SURVEY QUESTIONS AND EXPECTED ANSWERS
// This node extracts HR selections and prepares data for AI MCQ generation

const hrFormData = $input.first().json;

// Extract survey questions from earlier in the workflow
let surveyQuestions = [];
try {
  const surveyData = $('Process Survey Questions').first().json;
  surveyQuestions = surveyData.surveyQuestions || [];
  console.log(`✅ Retrieved ${surveyQuestions.length} survey questions from earlier node`);
  if (surveyQuestions.length > 0) {
    console.log('Survey questions found:', surveyQuestions.map(q => q.fieldLabel));
    console.log('Qualifying questions:', surveyQuestions.filter(q => q.isQualifying).map(q => `${q.fieldLabel} (expects: ${q.expectedAnswer})`));
  }
} catch (error) {
  console.log('No survey questions found, continuing without survey data');
  surveyQuestions = [];
}

// Get candidate data from earlier in workflow
let candidateData = {};
let jobRequirements = {};

try {
  const reviewData = $('Prepare HR Review Data').first().json;
  candidateData = reviewData;
  jobRequirements = reviewData.jobRequirements || {};
} catch (error) {
  console.log('Could not get candidate data, using defaults');
  jobRequirements = {
    title: 'Software Engineer',
    requiredSkills: 'Programming',
    optionalSkills: '',
    experienceLevel: '2-5 years'
  };
}

// Extract HR form selections
const selectedCandidateLabels = hrFormData['Select Candidates for Round 0 AI Screening'] || hrFormData.selected_candidates || [];
const focusAreas = hrFormData['Assessment Focus Areas'] || hrFormData.focus_areas || ['Comprehensive Assessment (All Areas)'];
const assessmentType = hrFormData['Assessment Configuration'] || hrFormData.assessment_type || ['Standard MCQ Assessment (20 questions)'];

console.log('HR Form Data:', JSON.stringify(hrFormData, null, 2));
console.log('Selected Candidates:', selectedCandidateLabels);
console.log('Focus Areas:', focusAreas);
console.log('Assessment Type:', assessmentType);
console.log(`Survey Questions to include: ${surveyQuestions.length}`);

// Process selected candidates
const allCandidates = candidateData.candidates || [];
const selectedCandidates = [];

selectedCandidateLabels.forEach(selectedLabel => {
  const candidate = allCandidates.find(c => c.selectionLabel === selectedLabel);
  if (candidate) {
    selectedCandidates.push({
      id: candidate.id,
      name: candidate.name,
      email: candidate.email,
      phone: candidate.phone,
      location: candidate.location,
      currentCompany: candidate.currentCompany,
      jobTitle: candidate.jobTitle,
      experienceYears: candidate.experienceYears,
      skills: candidate.skills,
      matchScore: candidate.matchScore,
      aiAnalysis: candidate.aiAnalysis,
      bio: candidate.bio,
      availability: candidate.availability,

      // Generate unique screening identifier
      screeningId: `screening_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,

      // Create expiration date (3 days from now)
      linkExpiration: new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString(),

      // Assessment status
      assessmentStatus: 'invited',
      invitedAt: new Date().toISOString()
    });
  }
});

console.log(`Processed ${selectedCandidates.length} selected candidates`);

// Question Pool Configuration
const questionsPerCandidate = 3;
const questionPoolSize = 5;

// Determine if coding questions should be included
const includeCoding = assessmentType.some(type => type.includes('coding challenge'));
const focusOnTechStack = assessmentType.some(type => type.includes('technology stack'));

// Generate comprehensive MCQ prompt for QUESTION POOL
const generateMCQPrompt = () => {
  const jobTitle = jobRequirements.title || 'Software Engineer';
  const jobDescription = jobRequirements.description || 'Standard software engineering role';
  const requiredSkills = jobRequirements.requiredSkills || 'Programming skills';
  const optionalSkills = jobRequirements.optionalSkills || 'None specified';
  const experienceLevel = jobRequirements.experienceLevel || '2-5 years';

  return `You are an expert Technical Assessment Designer. Create ${questionPoolSize} multiple-choice questions for a Round 0 AI Screening assessment QUESTION POOL.

**JOB CONTEXT:**
- **Position:** ${jobTitle}
- **Experience Level:** ${experienceLevel}
- **Required Skills:** ${requiredSkills}
- **Optional Skills:** ${optionalSkills}
- **Job Description:** ${jobDescription}

**SELECTED CANDIDATES:**
${selectedCandidates.map(c => `- ${c.name}: ${c.experienceYears} years experience, Skills: ${c.skills.slice(0, 3).join(', ')}, Match: ${c.matchScore}%`).join('\n')}

**ASSESSMENT FOCUS AREAS:**
${focusAreas.join(', ')}

**⭐ QUESTION POOL REQUIREMENTS:**
- **Total Pool Size:** ${questionPoolSize} questions
- **Per Candidate:** ${questionsPerCandidate} questions (randomly selected from pool)
- **Question Types:** Multiple choice (4 options each)
- **Difficulty:** Adjust based on ${experienceLevel} experience level
- **Include Coding:** ${includeCoding ? 'Yes - include programming logic questions' : 'No - focus on conceptual questions'}
- **Technology Focus:** ${focusOnTechStack ? 'Yes - emphasize specific technologies' : 'No - general technical knowledge'}

**QUESTION DISTRIBUTION FOR ${questionPoolSize} QUESTIONS:**
Create questions across these categories:

1. **Technical Skills (40%):** ${Math.round(questionPoolSize * 0.4)} questions
   - Programming concepts and ${requiredSkills}
   - Optional skills like ${optionalSkills} (when applicable)
   - Technology-specific knowledge

2. **Problem Solving (30%):** ${Math.round(questionPoolSize * 0.3)} questions
   - Logical reasoning and algorithms
   - System design concepts
   - Troubleshooting scenarios

3. **Domain Knowledge (20%):** ${Math.round(questionPoolSize * 0.2)} questions
   - Industry-specific knowledge for ${jobTitle}
   - Tools and frameworks
   - Current trends and practices

4. **Analytical Thinking (10%):** ${Math.round(questionPoolSize * 0.1)} questions
   - Data interpretation
   - Decision-making scenarios
   - Critical thinking

**OUTPUT FORMAT:**
Return a JSON object with this exact structure:

{
  "assessmentMetadata": {
    "jobTitle": "${jobTitle}",
    "targetExperience": "${experienceLevel}",
    "requiredSkills": "${requiredSkills}",
    "optionalSkills": "${optionalSkills}",
    "questionPoolSize": ${questionPoolSize},
    "questionsPerCandidate": ${questionsPerCandidate},
    "estimatedDuration": "${Math.round(questionsPerCandidate * 1.5)} minutes",
    "difficulty": "intermediate",
    "focusAreas": ${JSON.stringify(focusAreas)},
    "generatedAt": "${new Date().toISOString()}"
  },
  "questions": [
    {
      "id": 1,
      "category": "Technical Skills",
      "difficulty": "medium",
      "question": "What is the primary purpose of...",
      "options": {
        "A": "Option A text",
        "B": "Option B text", 
        "C": "Option C text",
        "D": "Option D text"
      },
      "correctAnswer": "A",
      "explanation": "Detailed explanation of why A is correct",
      "skillsTested": ["JavaScript", "Problem Solving"],
      "timeLimit": 90
    }
  ]
}

**QUALITY REQUIREMENTS:**
- Questions must be relevant to ${jobTitle} role specifically
- Focus on ${requiredSkills} as primary testing criteria
- Include ${optionalSkills} questions for comprehensive assessment
- Avoid questions that are too basic or too advanced for ${experienceLevel}
- Include practical, real-world scenarios
- Ensure each question has one clearly correct answer
- Make distractor options plausible but incorrect
- Add detailed explanations for learning purposes
- Test skills mentioned in: ${requiredSkills} and ${optionalSkills}
- CREATE VARIETY: Ensure questions are diverse enough that random selections create fair assessments

**ANTI-CHEATING CONSIDERATIONS:**
- Questions should require understanding, not just memorization
- Avoid questions easily answerable by search engines
- Include scenario-based questions requiring experience
- Make options specific enough to prevent guessing
- With ${questionPoolSize} questions, each candidate gets different subset

Generate exactly ${questionPoolSize} high-quality questions following this specification.`;
};

// Create the AI prompt
const mcqPrompt = generateMCQPrompt();

// Generate screening links for each candidate
const screeningLinks = selectedCandidates.map(candidate => ({
  candidateId: candidate.screeningId,
  candidateName: candidate.name,
  candidateEmail: candidate.email,

  // Generate unique screening URL (this would be your assessment platform URL)
  screeningUrl: `http://127.0.0.1:5500/assessment_html_page.html?id=${candidate.screeningId}`,

  // Backup/direct link format
  directLink: `https://your-domain.com/assessment?id=${candidate.screeningId}&token=${Buffer.from(candidate.email + candidate.screeningId).toString('base64')}`,

  // Link metadata
  expiresAt: candidate.linkExpiration,
  generatedAt: new Date().toISOString(),
  isActive: true
}));

// Prepare email data for each candidate with survey questions
const emailTasks = selectedCandidates.map((candidate, index) => {
  const screeningLink = screeningLinks[index];

  // ✅ Generate survey questions section for email with expected answers
  let surveyQuestionsHtml = '';
  if (surveyQuestions.length > 0) {
    const qualifyingQuestions = surveyQuestions.filter(q => q.isQualifying);
    const informationalQuestions = surveyQuestions.filter(q => !q.isQualifying);

    surveyQuestionsHtml = `
      <div style="background: #f0f8ff; border: 2px solid #007bff; border-radius: 8px; padding: 20px; margin-bottom: 20px;">
        <h3 style="margin: 0 0 15px 0; color: #0066cc;">📋 Two-Stage Assessment Process</h3>
        <p style="margin: 0 0 10px 0; color: #495057;"><strong>Stage 1: Preference Screening</strong></p>
        <p style="margin: 0 0 15px 0; color: #495057;">You must answer these qualifying questions correctly to proceed to the technical round:</p>`;

    if (qualifyingQuestions.length > 0) {
      surveyQuestionsHtml += `<ul style="margin: 0 0 15px 0; padding-left: 20px; color: #495057;">`;
      qualifyingQuestions.forEach(q => {
        let optionText = '';
        if (q.fieldOptions && q.fieldOptions.values) {
          optionText = ` (${q.fieldOptions.values.map(opt => opt.option).join(' / ')})`;
        }
        surveyQuestionsHtml += `<li><strong>✅ ${q.fieldLabel}</strong>${optionText} - <em>Qualifying Question</em></li>`;
      });
      surveyQuestionsHtml += `</ul>`;
    }

    if (informationalQuestions.length > 0) {
      surveyQuestionsHtml += `<p style="margin: 15px 0 10px 0; color: #495057;"><strong>Additional Information Questions:</strong></p>`;
      surveyQuestionsHtml += `<ul style="margin: 0 0 15px 0; padding-left: 20px; color: #495057;">`;
      informationalQuestions.forEach(q => {
        let optionText = '';
        if (q.fieldOptions && q.fieldOptions.values) {
          optionText = ` (${q.fieldOptions.values.map(opt => opt.option).join(' / ')})`;
        }
        surveyQuestionsHtml += `<li><strong>ℹ️ ${q.fieldLabel}</strong>${optionText} - <em>For our reference only</em></li>`;
      });
      surveyQuestionsHtml += `</ul>`;
    }

    surveyQuestionsHtml += `
        <p style="margin: 10px 0 0 0; font-size: 12px; color: #6c757d; font-style: italic;">
          <strong>Important:</strong> You must pass the preference screening to access the technical assessment.
        </p>
      </div>`;
  }

  return {
    to: candidate.email,
    candidateName: candidate.name,
    subject: `Two-Stage Assessment Invitation - ${jobRequirements.title} Position`,

    // ✅ Enhanced email body with survey questions and expected answers info
    emailBody: `
    <div style="font-family: 'Segoe UI', Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px; background: #f8f9fa;">

      <!-- Header -->
      <div style="background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); color: white; padding: 30px; border-radius: 12px; text-align: center; margin-bottom: 25px;">
        <h1 style="margin: 0; font-size: 24px;">🎯 Two-Stage Assessment Invitation</h1>
        <p style="margin: 10px 0 0 0; font-size: 16px; opacity: 0.9;">${jobRequirements.title} Position</p>
      </div>

      <!-- Personal Greeting -->
      <div style="background: white; padding: 25px; border-radius: 8px; margin-bottom: 20px; border-left: 4px solid #007bff;">
        <p style="margin: 0 0 15px 0; font-size: 16px;">Dear <strong>${candidate.name}</strong>,</p>
        <p style="margin: 0; color: #495057; line-height: 1.6;">
          Congratulations! Based on your profile and experience at <strong>${candidate.currentCompany}</strong>, 
          you have been selected for our comprehensive two-stage assessment process.
        </p>
      </div>

      <!-- Assessment Details -->
      <div style="background: white; padding: 25px; border-radius: 8px; margin-bottom: 20px;">
        <h3 style="margin: 0 0 15px 0; color: #2c3e50;">📋 Assessment Overview</h3>
        <ul style="margin: 0; padding-left: 20px; color: #495057; line-height: 1.8;">
          <li><strong>Position:</strong> ${jobRequirements.title}</li>
          <li><strong>Required Skills Focus:</strong> ${jobRequirements.requiredSkills}</li>
          ${jobRequirements.optionalSkills && jobRequirements.optionalSkills !== 'None specified' ? 
            `<li><strong>Bonus Skills:</strong> ${jobRequirements.optionalSkills}</li>` : ''}
          <li><strong>Format:</strong> Two-Stage Process (Preference Screening + Technical MCQ)</li>
          <li><strong>Technical Questions:</strong> ${questionsPerCandidate} multiple choice questions</li>
          <li><strong>Duration:</strong> Approximately ${Math.round(questionsPerCandidate * 1.5)} minutes for technical round</li>
          <li><strong>Focus Areas:</strong> ${focusAreas.join(', ')}</li>
          <li><strong>Proctoring:</strong> Camera monitoring enabled for technical round</li>
        </ul>
      </div>

      <!-- ✅ Survey Questions Section with Expected Answers -->
      ${surveyQuestionsHtml}

      <!-- Access Link -->
      <div style="background: #e7f3ff; border: 2px solid #007bff; border-radius: 8px; padding: 25px; margin-bottom: 20px; text-align: center;">
        <h3 style="margin: 0 0 15px 0; color: #0066cc;">🔗 Your Assessment Link</h3>
        <a href="${screeningLink.screeningUrl}" 
           style="display: inline-block; background: #007bff; color: white; padding: 15px 30px; border-radius: 6px; text-decoration: none; font-weight: bold; margin: 10px 0;">
          Start Two-Stage Assessment
        </a>
        <p style="margin: 15px 0 0 0; font-size: 14px; color: #495057;">
          <strong>Assessment ID:</strong> ${candidate.screeningId}<br>
          <strong>Expires:</strong> ${new Date(candidate.linkExpiration).toLocaleDateString()} at ${new Date(candidate.linkExpiration).toLocaleTimeString()}
        </p>
      </div>

      <!-- Important Instructions -->
      <div style="background: #fff3cd; border: 1px solid #ffeaa7; border-radius: 8px; padding: 20px; margin-bottom: 20px;">
        <h3 style="margin: 0 0 15px 0; color: #856404;">⚠️ Important Instructions</h3>
        <ul style="margin: 0; padding-left: 20px; color: #856404; font-size: 14px; line-height: 1.6;">
          <li><strong>Two-Stage Process:</strong> Complete preference screening first, then technical assessment</li>
          <li><strong>Qualifying Questions:</strong> You must answer preference questions correctly to proceed</li>
          <li><strong>Camera Required:</strong> Ensure your camera works for the technical round</li>
          <li><strong>Stable Internet:</strong> Use a reliable internet connection</li>
          <li><strong>Quiet Environment:</strong> Choose a distraction-free location</li>
          <li><strong>No External Help:</strong> Assessment must be completed independently</li>
          <li><strong>Single Attempt:</strong> You can only take this assessment once</li>
          <li><strong>Time Limit:</strong> Complete within 3 days of receiving this email</li>
        </ul>
      </div>

      <!-- Contact Information -->
      <div style="background: #f8f9fa; padding: 20px; border-radius: 8px; text-align: center;">
        <p style="margin: 0 0 10px 0; color: #6c757d; font-size: 14px;">
          If you have any technical issues or questions, please contact our HR team.
        </p>
        <p style="margin: 0; color: #6c757d; font-size: 14px;">
          <strong>Best of luck with your two-stage assessment!</strong>
        </p>
      </div>

    </div>`,

    // ✅ Enhanced metadata with survey questions and expected answers
    screeningId: candidate.screeningId,
    surveyQuestions: surveyQuestions, // Include survey questions for storage
    assessmentMetadata: {
      candidateMatchScore: candidate.matchScore,
      candidateSkills: candidate.skills,
      questionCount: questionsPerCandidate,
      surveyQuestionCount: surveyQuestions.length,
      qualifyingSurveyQuestionCount: surveyQuestions.filter(q => q.isQualifying).length,
      informationalSurveyQuestionCount: surveyQuestions.filter(q => !q.isQualifying).length,
      focusAreas: focusAreas,
      assessmentType: assessmentType
    }
  };
});

// Return comprehensive data for next workflow steps
return [{
  json: {
    // AI MCQ Generation Prompt
    mcqPrompt: mcqPrompt,

    // Processed selections
    selectedCandidates: selectedCandidates,
    candidateCount: selectedCandidates.length,

    // ✅ Survey questions data with expected answers
    surveyQuestions: surveyQuestions,

    // Assessment configuration
    assessmentConfig: {
      questionPoolSize: questionPoolSize,
      questionsPerCandidate: questionsPerCandidate,
      surveyQuestionCount: surveyQuestions.length,
      qualifyingSurveyQuestionCount: surveyQuestions.filter(q => q.isQualifying).length,
      informationalSurveyQuestionCount: surveyQuestions.filter(q => !q.isQualifying).length,
      focusAreas: focusAreas,
      assessmentType: assessmentType,
      includeCoding: includeCoding,
      focusOnTechStack: focusOnTechStack,
      estimatedDuration: Math.round(questionsPerCandidate * 1.5)
    },

    // Job context
    jobRequirements: jobRequirements,

    // Screening links
    screeningLinks: screeningLinks,

    // Email tasks ready for sending (now includes survey questions with expected answers)
    emailTasks: emailTasks,

    // Summary data
    processingSummary: {
      totalCandidatesSelected: selectedCandidates.length,
      questionPoolSize: questionPoolSize,
      questionsPerCandidate: questionsPerCandidate,
      surveyQuestionsIncluded: surveyQuestions.length,
      qualifyingSurveyQuestionsIncluded: surveyQuestions.filter(q => q.isQualifying).length,
      informationalSurveyQuestionsIncluded: surveyQuestions.filter(q => !q.isQualifying).length,
      assessmentDuration: Math.round(questionsPerCandidate * 1.5),
      linkExpirationDays: 3,
      focusAreasCount: focusAreas.length,
      emailsToSend: emailTasks.length,
      processedAt: new Date().toISOString()
    },

    // Next step instructions
    nextSteps: [
      `1. Use mcqPrompt with AI Agent to generate ${questionPoolSize} questions`,
      "2. Send emails using emailTasks data (includes survey questions with expected answers)", 
      "3. Store screening links for candidate access tracking",
      "4. Set up assessment platform to handle two-stage process",
      `5. Survey questions: ${surveyQuestions.filter(q => q.isQualifying).length} qualifying + ${surveyQuestions.filter(q => !q.isQualifying).length} informational`
    ],

    // Debug information
    debugInfo: {
      hrFormReceived: Object.keys(hrFormData),
      selectedLabels: selectedCandidateLabels,
      candidatesFound: selectedCandidates.length,
      emailsGenerated: emailTasks.length,
      promptLength: mcqPrompt.length,
      questionPoolEnabled: true,
      surveyQuestionsFound: surveyQuestions.length,
      qualifyingSurveyQuestionsFound: surveyQuestions.filter(q => q.isQualifying).length,
      informationalSurveyQuestionsFound: surveyQuestions.filter(q => !q.isQualifying).length,
      surveyQuestionDetails: surveyQuestions.map(q => ({ 
        label: q.fieldLabel, 
        type: q.fieldType,
        isQualifying: q.isQualifying,
        expectedAnswer: q.expectedAnswer
      }))
    }
  }
}];

// Parse MCQ Output & Prepare Email Data - FIXED VERSION
const mcqResponse = $input.first().json;
const mcqGenerationData = $('Process Selections & Generate MCQ').first().json;

// Extract MCQ questions from AI response
let mcqQuestions = [];
let assessmentMetadata = {};

try {
  const outputText = mcqResponse.output;
  const cleanedOutput = outputText.replace(/```json\n|\n```|```/g, '').trim();
  const parsedMCQ = JSON.parse(cleanedOutput);

  mcqQuestions = parsedMCQ.questions || [];
  assessmentMetadata = parsedMCQ.assessmentMetadata || {};

  console.log(`Successfully parsed ${mcqQuestions.length} MCQ questions`);

} catch (error) {
  console.log('Error parsing MCQ JSON:', error.message);
  return [{
    json: {
      error: 'Failed to parse MCQ questions',
      details: error.message,
      rawOutput: mcqResponse.output
    }
  }];
}

const emailTasks = mcqGenerationData.emailTasks || [];
const selectedCandidates = mcqGenerationData.selectedCandidates || [];

const enhancedEmailTasks = emailTasks.map((emailTask, index) => {

  const matchingCandidate = selectedCandidates.find(c => c.email === emailTask.to);
  const screeningId = matchingCandidate?.screeningId || emailTask.screeningId;

  // ✅ ENHANCED: More aggressive removal of all instruction blocks
  let updatedBody = emailTask.emailBody;
  // Remove all variations of Important Instructions blocks
  updatedBody = updatedBody.replace(/⚠️\s*Important Instructions[\s\S]*?(?=🔗|<a href|Assessment ID:|<\/div>\s*<\/div>)/gi, '');
  // Remove Two-Stage Assessment Process blocks
  updatedBody = updatedBody.replace(/📋\s*Two-Stage Assessment Process[\s\S]*?(?=🔗|<a href|Assessment ID:|<\/div>\s*<\/div>)/gi, '');
  // Remove any orphaned instruction list items or divs
  updatedBody = updatedBody.replace(/<div[^>]*>\s*<h3[^>]*>⚠️[^<]*Important Instructions[^<]*<\/h3>[\s\S]*?<\/div>/gi, '');
  updatedBody = updatedBody.replace(/<div[^>]*>\s*<h3[^>]*>📋[^<]*Two-Stage[^<]*<\/h3>[\s\S]*?<\/div>/gi, '');
  // Remove Proctoring line
  updatedBody = updatedBody.replace(/<li>\s*<strong>Proctoring:<\/strong>.*?<\/li>/gi, '');
  updatedBody = updatedBody.replace(/•?\s*Proctoring:.*?Camera monitoring enabled for technical round\s*/gi, '');
  // Clean up multiple line breaks
  updatedBody = updatedBody.replace(/\n{3,}/g, '\n\n');
  updatedBody = updatedBody.trim();

  // Build fresh instructions block with proper bullet points in HTML
  const instructionsBlock = `
<div style="background: #e7f3ff; border: 2px solid #007bff; border-radius: 8px; padding: 20px; margin-bottom: 20px;">
<h3 style="margin: 0 0 15px 0; color: #0066cc;">⚠️ Important Instructions</h3>
<ul style="margin: 0; padding-left: 20px; color: #495057; line-height: 1.8;">
<li><strong>Two-Stage Process:</strong> Complete preference screening first, then technical assessment</li>
<li><strong>Qualifying Questions:</strong> Must be passed to unlock technical exam</li>
<li><strong>Camera Required:</strong> Ensure your camera works for the technical round</li>
<li><strong>Stable Internet:</strong> Use a reliable internet connection</li>
<li><strong>Quiet Environment:</strong> Choose a distraction-free location</li>
<li><strong>No External Help:</strong> Assessment must be completed independently</li>
<li><strong>Single Attempt:</strong> You can only take this assessment once</li>
<li><strong>Time Limit:</strong> Complete within 3 days of receiving this email</li>
</ul>
</div>
`;

  // Insert instructions ONLY above the link section - try multiple markers
  if (updatedBody.includes('🔗 Your Assessment Link')) {
    updatedBody = updatedBody.replace('🔗 Your Assessment Link', `${instructionsBlock}\n🔗 Your Assessment Link`);
  } else if (updatedBody.includes('<h3')) {
    // If no link marker found, insert before the first remaining h3 tag that contains 🔗
    updatedBody = updatedBody.replace(/(<h3[^>]*>🔗)/i, `${instructionsBlock}\n$1`);
  } else if (updatedBody.includes('Start Two-Stage Assessment')) {
    updatedBody = updatedBody.replace('Start Two-Stage Assessment', `${instructionsBlock}\n\nStart Two-Stage Assessment`);
  }

  return {
    ...emailTask,
    screeningId,
    enhancedEmailBody: updatedBody
