// Helper function to extract years from experience string (keep existing)
function extractYearsFromExperience(experienceStr) {
  const matches = experienceStr.match(/(\d+)(?:-(\d+))?\s*years?/i);
  if (matches) {
    const min = parseInt(matches[1]);
    const max = matches[2] ? parseInt(matches[2]) : min;
    return { min, max };
  }
  return { min: 2, max: 5 }; // default
}

