// Helper functions (keep existing)
function getTopSkills(candidates) {
  const skillCounts = {};
  candidates.forEach(candidate => {
    (candidate.skills || []).forEach(skill => {
      skillCounts[skill] = (skillCounts[skill] || 0) + 1;
    });
  });

  return Object.entries(skillCounts)
    .sort(([,a], [,b]) => b - a)
    .slice(0, 8)
    .map(([skill, count]) => ({ skill, count }));
}

function getRecommendationBreakdown(candidates) {
  const breakdown = {};
  candidates.forEach(candidate => {
    const action = candidate.aiAnalysis.recommendedAction || 'Review';
    breakdown[action] = (breakdown[action] || 0) + 1;
  });
  return breakdown;
}

function getExperienceBreakdown(candidates) {
  const breakdown = {};
  candidates.forEach(candidate => {
    const fit = candidate.aiAnalysis.experienceFit || 'Unknown';
    breakdown[fit] = (breakdown[fit] || 0) + 1;
  });
  return breakdown;
}

