    analysis += `${emoji} ${index + 1}. ${candidate.name} (${candidate.matchScore}% overall match)\n`;
    analysis += `   📍 ${candidate.currentCompany} | 💼 ${candidate.experienceYears} years experience | 📧 ${candidate.email}\n`;
    analysis += `   🛠️ Skills: ${candidate.skillsDisplay}\n`;
    analysis += `   🎯 Required Skills Coverage: ${candidate.aiAnalysis.requiredSkillsCoverage} (${candidate.aiAnalysis.skillMatchPercentage}%)\n`;

    if (candidate.aiAnalysis.matchedOptionalSkills.length > 0) {
      analysis += `   ⭐ Optional Skills Bonus: ${candidate.aiAnalysis.matchedOptionalSkills.join(', ')}\n`;
    }

    analysis += `   🏆 AI Recommendation: ${candidate.aiAnalysis.recommendedAction} | Experience Fit: ${candidate.aiAnalysis.experienceFit}\n`;

    // Key strengths
    if (candidate.aiAnalysis.keyStrengths && candidate.aiAnalysis.keyStrengths.length > 0) {
      analysis += `   💪 Strengths: ${candidate.aiAnalysis.keyStrengths.slice(0, 2).join(', ')}\n`;
    }

    // Concerns
    if (candidate.aiAnalysis.concerns && candidate.aiAnalysis.concerns.length > 0) {
      analysis += `   ⚠️ Considerations: ${candidate.aiAnalysis.concerns.slice(0, 1).join(', ')}\n`;
    }

    // AI reasoning summary
    if (candidate.aiAnalysis.reasoning) {
      const shortReasoning = candidate.aiAnalysis.reasoning.length > 120 ? 
        candidate.aiAnalysis.reasoning.substring(0, 120) + '...' : 
        candidate.aiAnalysis.reasoning;
      analysis += `   🤖 AI Analysis: ${shortReasoning}\n`;
    }

    if (index < enrichedCandidates.length - 1) {
      analysis += `\n`;
    }
  });

  // Enhanced instructions
  analysis += `\n`;
  analysis += `💡 SELECTION GUIDANCE:\n`;
  analysis += `• SELECT multiple candidates for Round 0 AI screening from the dropdown below\n`;
  analysis += `• Candidates are pre-ranked by AI match score (highest first)\n`;
  analysis += `• Consider both required skills coverage AND experience fit\n`;
  analysis += `• Optional skills provide bonus points but are not mandatory\n`;
  analysis += `• "Strong hire" and "Interview" recommendations are preferred choices\n`;
  analysis += `• Each selected candidate will receive unique assessment questions`;

  // ✅ NEW: Add survey questions note
  if (surveyQuestions.length > 0) {
    analysis += `\n• Selected candidates will also answer ${surveyQuestions.length} custom survey question(s) listed above`;
  }

  return analysis;
};

const formAnalysis = generateFormAnalysis();

// Generate enhanced form title
const formTitle = `Candidate Review - ${jobRequirements.title || 'Position'} (${summaryStats.totalCandidates} candidates | Avg: ${summaryStats.averageMatchScore}% | ${summaryStats.excellentMatches} excellent)`;

console.log(`✅ ENHANCED ANALYSIS GENERATED:`);
console.log(`  - Candidates analyzed: ${enrichedCandidates.length}`);
console.log(`  - Survey questions found: ${surveyQuestions.length}`);
console.log(`  - Job: ${jobRequirements.title}`);
console.log(`  - Top candidate: ${enrichedCandidates[0]?.name} (${enrichedCandidates[0]?.matchScore}%)`);

// ✅ Return enhanced formatted data with survey questions
return [{
  json: {
    // Structured data for next nodes
    candidates: enrichedCandidates,
    summaryStats: summaryStats,
    jobRequirements: jobRequirements,

    // ✅ NEW: Include survey questions
    surveyQuestions: surveyQuestions,

    // ✅ Enhanced form configuration
    formTitle: formTitle,
    formDescription: formAnalysis,

    // Processing metadata
    totalCandidates: enrichedCandidates.length,
    processedAt: new Date().toISOString(),
    readyForHRReview: true,
    enhancedAnalysis: true,

    // Debug info
    debugInfo: {
      jobRequirements: jobRequirements,
      candidateCount: enrichedCandidates.length,
      surveyQuestionsCount: surveyQuestions.length, // ✅ NEW
      averageMatchScore: summaryStats.averageMatchScore,
      topCandidate: enrichedCandidates[0]?.name || 'None',
      analysisGenerated: true,
      dropdownOptionsCount: enrichedCandidates.length,
      formAnalysisLength: formAnalysis.length,
      enhancementsApplied: true,
      surveyQuestionsIncluded: surveyQuestions.length > 0 // ✅ NEW
    }
  }
}];

