<script>
document.addEventListener('DOMContentLoaded', function() {
    console.log('🎨 Enhanced Form: Initializing...');

    // Wait longer for n8n form to fully render
    setTimeout(function() {
        console.log('🔍 Starting form enhancement...');

        // Find all elements
        const allLabels = document.querySelectorAll('label');
        const allSelects = document.querySelectorAll('select');

        console.log(`Found ${allLabels.length} labels and ${allSelects.length} selects`);

        if (allSelects.length >= 4) {
            // Identify elements
            const skillFilter = allSelects[0];
            const scoreFilter = allSelects[1];
            const recommendationFilter = allSelects[2];
            const candidateSelect = allSelects[3];

            // Get corresponding labels
            const skillLabel = allLabels[0];
            const scoreLabel = allLabels[1];
            const recommendationLabel = allLabels[2];
            const candidateLabel = allLabels[3];

            console.log('✅ Found all form elements');

            // Store original candidates
            const allOptions = Array.from(candidateSelect.options);
            console.log(`📊 Stored ${allOptions.length} candidate options`);

            // Create filters container
            const filtersContainer = document.createElement('div');
            filtersContainer.className = 'filters-row';

            // Create filter groups
            function createFilterGroup(label, select, name) {
                const group = document.createElement('div');
                group.className = 'filter-group';

                // Enhanced label
                const newLabel = document.createElement('div');
                newLabel.className = 'filter-label';
                newLabel.textContent = label.textContent;

                // Info div
                const info = document.createElement('div');
                info.className = 'filter-info';
                info.textContent = `Filter by ${name}`;

                group.appendChild(newLabel);
                group.appendChild(select);
                group.appendChild(info);

                return group;
            }

            // Create the three filter groups
            const skillGroup = createFilterGroup(skillLabel, skillFilter, 'skills');
            const scoreGroup = createFilterGroup(scoreLabel, scoreFilter, 'scores');
            const recommendationGroup = createFilterGroup(recommendationLabel, recommendationFilter, 'recommendations');

            // Add groups to container
            filtersContainer.appendChild(skillGroup);
            filtersContainer.appendChild(scoreGroup);
            filtersContainer.appendChild(recommendationGroup);

            // Insert filters container at the top
            const formContainer = candidateSelect.closest('form') || document.body;
            const firstElement = formContainer.querySelector('label, select, .form-description');
            if (firstElement) {
                firstElement.parentNode.insertBefore(filtersContainer, firstElement);
            }

            // Remove original labels (they're now in the groups)
            [skillLabel, scoreLabel, recommendationLabel].forEach(label => {
                if (label && label.parentNode) {
                    label.parentNode.removeChild(label);
                }
            });

            // Enhance candidate selection label
            if (candidateLabel) {
                candidateLabel.className = 'main-selection-label';
            }

            // Add candidate counter
            const counter = document.createElement('div');
            counter.className = 'candidate-counter';
            counter.textContent = `👥 Showing ${allOptions.length} candidates`;
            candidateSelect.parentNode.insertBefore(counter, candidateSelect);

            // Filter function
            function applyFilters() {
                const skillValue = skillFilter.value;
                const scoreValue = scoreFilter.value;
                const recommendationValue = recommendationFilter.value;

                console.log('🎯 Applying filters:', { skillValue, scoreValue, recommendationValue });

                candidateSelect.innerHTML = '';
                let count = 0;

                allOptions.forEach(option => {
                    let include = true;
                    const text = option.textContent.toLowerCase();

                    // Skill filter
                    if (skillValue && skillValue !== 'All Candidates') {
                        if (!text.includes(skillValue.toLowerCase())) {
                            include = false;
                        }
                    }

                    // Score filter
                    if (scoreValue && scoreValue !== 'All Scores') {
                        const scoreMatch = text.match(/(\\d+)% match/);
                        if (scoreMatch) {
                            const score = parseInt(scoreMatch[1]);
                            switch(scoreValue) {
                                case 'Excellent (80%+)':
                                    if (score < 80) include = false;
                                    break;
                                case 'Good (60-79%)':
                                    if (score < 60 || score >= 80) include = false;
                                    break;
                                case 'Average (40-59%)':
                                    if (score < 40 || score >= 60) include = false;
                                    break;
                                case 'Below Average (<40%)':
                                    if (score >= 40) include = false;
                                    break;
                            }
                        }
                    }

                    // Recommendation filter
                    if (recommendationValue && recommendationValue !== 'All Recommendations') {
                        if (!text.includes(recommendationValue.toLowerCase())) {
                            include = false;
                        }
                    }

                    if (include) {
                        candidateSelect.appendChild(option.cloneNode(true));
                        count++;
                    }
                });

                // Update counter
                counter.textContent = `👥 Showing ${count} of ${allOptions.length} candidates`;
                counter.className = count < allOptions.length ? 'candidate-counter filtered' : 'candidate-counter';

                // Clear selections
                Array.from(candidateSelect.options).forEach(opt => opt.selected = false);

                // Update filter info
                document.querySelectorAll('.filter-info').forEach((info, index) => {
                    const values = [skillValue, scoreValue, recommendationValue];
                    const defaults = ['All Candidates', 'All Scores', 'All Recommendations'];
                    const names = ['skills', 'scores', 'recommendations'];

                    if (values[index] && values[index] !== defaults[index]) {
                        info.textContent = `Active: ${values[index]}`;
                        info.classList.add('active');
                    } else {
                        info.textContent = `Filter by ${names[index]}`;
                        info.classList.remove('active');
                    }
                });

                console.log(`✅ Showing ${count} candidates`);
            }

            // Add event listeners
            skillFilter.addEventListener('change', applyFilters);
            scoreFilter.addEventListener('change', applyFilters);
            recommendationFilter.addEventListener('change', applyFilters);

            console.log('✅ Form enhancement complete!');

        } else {
            console.warn('⚠️ Not enough form elements found');
        }

    }, 2000); // Increased timeout for n8n form loading
});
</script>

