// FIXED: Process Survey Questions Code - Remove Overly Strict Validation
const inputData = $input.first().json;

console.log('=== PROCESSING SURVEY QUESTIONS WITH EXPECTED ANSWERS (FIXED) ===');

// The form data is nested in originalFormData
const formData = inputData.originalFormData || inputData;
console.log('Form Data Keys:', Object.keys(formData));

// Extract survey questions (up to 5) with expected answers
const surveyQuestions = [];

for (let i = 1; i <= 5; i++) {
  const questionText = formData[`Survey Question ${i} (Optional)`];
  const questionType = formData[`Survey Question ${i} Type`];
  const questionOptions = formData[`Survey Question ${i} Options (For Multiple Choice)`];
  const expectedAnswer = formData[`Survey Question ${i} - Expected Answer`]; // ✅ FIXED: Use correct field name

  console.log(`Checking Survey Question ${i}:`, {
    questionText,
    questionType,
    questionOptions,
    expectedAnswer
  });

  // Only process if question text exists and is not empty
  if (questionText && questionText.trim() !== '') {
    console.log(`✅ Processing Survey Question ${i}:`, questionText);

    let fieldConfig = {
      fieldLabel: questionText.trim(),
      requiredField: false,
      isSurveyQuestion: true,
      surveyQuestionId: i,
      expectedAnswer: expectedAnswer ? expectedAnswer.trim() : null, // ✅ PRESERVE expected answer
      isQualifying: !!(expectedAnswer && expectedAnswer.trim()), // Qualifying if has expected answer
      questionCategory: (expectedAnswer && expectedAnswer.trim()) ? 'qualifying' : 'informational',
      validationType: (expectedAnswer && expectedAnswer.trim()) ? 'exact_match' : 'none'
    };

    // Configure field type based on selection
    switch (questionType) {
      case 'Yes/No':
        fieldConfig.fieldType = 'dropdown';
        fieldConfig.fieldOptions = {
          values: [
            { option: 'Yes' },
            { option: 'No' }
          ]
        };
        fieldConfig.multiselect = false;

        // ✅ FIXED: More lenient validation - don't nullify if invalid
        if (fieldConfig.expectedAnswer && !['Yes', 'No', 'yes', 'no', 'YES', 'NO'].includes(fieldConfig.expectedAnswer)) {
          console.warn(`Expected answer "${fieldConfig.expectedAnswer}" for Yes/No question ${i} - keeping as is for manual review`);
          // Don't nullify - let it pass through for manual review
        }

        console.log(`  → Configured as Yes/No dropdown, Expected: ${fieldConfig.expectedAnswer || 'None'}`);
        break;

      case 'Multiple Choice':
        fieldConfig.fieldType = 'dropdown';
        if (questionOptions && questionOptions.trim() !== '') {
          // Split options by comma and create dropdown values
          const options = questionOptions.split(',').map(opt => ({
            option: opt.trim()
          })).filter(opt => opt.option !== '');

          fieldConfig.fieldOptions = { values: options };

          // ✅ FIXED: More lenient validation for Multiple Choice
          if (fieldConfig.expectedAnswer) {
            const validOptions = options.map(opt => opt.option);
            if (!validOptions.includes(fieldConfig.expectedAnswer)) {
              console.warn(`Expected answer "${fieldConfig.expectedAnswer}" not in options [${validOptions.join(', ')}] for question ${i} - keeping as is for manual review`);
              // Don't nullify - let it pass through
            }
          }

          console.log(`  → Configured as Multiple Choice with ${options.length} options, Expected: ${fieldConfig.expectedAnswer || 'None'}`);
        } else {
          // Default options if none provided
          fieldConfig.fieldOptions = {
            values: [
              { option: 'Option 1' },
              { option: 'Option 2' },
              { option: 'Option 3' }
            ]
          };
          // ✅ FIXED: Don't nullify expected answer even for default options
          console.log(`  → Using default Multiple Choice options, Expected: ${fieldConfig.expectedAnswer || 'None'}`);
        }
        fieldConfig.multiselect = false;
        break;

      case 'Text Input':
      default:
        // Text input - always allow expected answer to pass through
        fieldConfig.fieldType = 'text';
        fieldConfig.placeholder = 'Please provide your answer...';
        // ✅ FIXED: Don't nullify expected answer for text inputs
        console.log(`  → Configured as Text Input, Expected: ${fieldConfig.expectedAnswer || 'None'}`);
        break;
    }

    surveyQuestions.push(fieldConfig);
  }
}

// Count qualifying vs informational questions
const qualifyingCount = surveyQuestions.filter(q => q.isQualifying).length;
const informationalCount = surveyQuestions.filter(q => !q.isQualifying).length;

console.log(`✅ FINAL RESULT: Processed ${surveyQuestions.length} survey questions`);
console.log(`  - Qualifying questions (with expected answers): ${qualifyingCount}`);
console.log(`  - Informational questions: ${informationalCount}`);

if (surveyQuestions.length > 0) {
  console.log('Survey Questions Created:');
  surveyQuestions.forEach((q, index) => {
    console.log(`  ${index + 1}. ${q.fieldLabel} (${q.questionCategory}${q.expectedAnswer ? `, expects: "${q.expectedAnswer}"` : ''}) - Type: ${q.fieldType}`);
  });
}

// Return the original data plus the processed survey questions
return [{
  json: {
    // Keep all existing data from the input
    ...inputData,

    // Add/update survey questions with expected answers
    surveyQuestions: surveyQuestions,

    // Update survey metadata
    surveyMetadata: {
      totalQuestions: surveyQuestions.length,
      qualifyingQuestions: qualifyingCount,
      informationalQuestions: informationalCount,
      questionTypes: surveyQuestions.map(q => q.fieldType),
      expectedAnswers: surveyQuestions.filter(q => q.expectedAnswer).map(q => ({
        question: q.fieldLabel,
        expectedAnswer: q.expectedAnswer,
        type: q.fieldType
      })),
      generatedAt: new Date().toISOString(),
      rawFormData: formData
    },

    // Update debug info
    debugInfo: {
      ...inputData.debugInfo,
      surveyQuestionsFound: surveyQuestions.length,
      qualifyingQuestionsFound: qualifyingCount,
      informationalQuestionsFound: informationalCount,
      surveyProcessingSuccess: true,
      expectedAnswersConfigured: surveyQuestions.filter(q => q.expectedAnswer).length,
      formDataSource: inputData.originalFormData ? 'originalFormData' : 'direct',
      validationFixed: true
    }
  }
}];
